//HELPER FUNCTIONS
short darkenColor(short color) {
    int r = (color >> 11) & 0x1F;
    int g = (color >> 5)  & 0x3F;
    int b = color & 0x1F;

    r = (r * 7) / 10;  // ~0.7
    g = (g * 7) / 10;
    b = (b * 7) / 10;

    return (r << 11) | (g << 5) | b;
}

